#include <bits/stdc++.h>using namespace std;typedef long long ll;bool check(ll mid,ll h,vector<ll>& a){    ll sum=0;    ll mn=INT_MAX;    for(int i = 0; i <= mid; i++) {        sum+=a[i];        mn=min(mn,a[i]);    }    ll mx=0;    for(int i = mid+1; i < a.size(); i++) {        mx=max(mx,a[i]);    }    sum=sum+max(0LL,mx-mn);    return sum>=h;}int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int t;    cin >> t;    while(t--) {        ll n,h,k;        cin >> n >> h >> k;        vector<ll> a(n);        ll sum=0;        for(int i = 0; i < n; i++) {            cin >> a[i];            sum+=a[i];        }        ll ans=0;        ans+=(n*(h/sum))+((h/sum)*k);        if(h%sum==0){            cout << ans-k << endl;            continue;        }        ll rem=h%sum;        ll add=-1;        ll lo=0;        ll hi=n-1;        while(lo<=hi){            ll mid=lo+(hi-lo)/2;            if(check(mid,rem,a)){                add=mid;                hi=mid-1;            }            else{                lo=mid+1;            }        }        ans+=add+1;        cout << ans << endl;    }    return 0;}